```

#### Implementation
```rust
impl ShutdownDisplay {
    const SPINNER_FRAMES: &[char] = &['◐', '◓', '◑', '◒'];

    pub fn display(&self, progress: &ShutdownProgress, frame: usize) {
        let output = RichOutput::global();

        // Skip rendering entirely if agent mode and no TTY
        if \!output.should_render() {
            self.display_plain(&output, progress);
            return;
        }

        let theme = output.theme();
        let mut content = Vec::new();

        // Stage indicator with spinner
        let stage_text = match progress.stage {
            ShutdownStage::SignalReceived => "Signal received, initiating shutdown...",
            ShutdownStage::StopAccepting => "Stopped accepting new connections",
            ShutdownStage::DrainingConnections => "Draining connections...",
            ShutdownStage::WaitingForTasks => "Waiting for background tasks...",
            ShutdownStage::CleaningResources => "Cleaning up resources...",
            ShutdownStage::Complete => "Shutdown complete",
        };

        let icon = if matches\!(progress.stage, ShutdownStage::Complete) {
            theme.style_text("✓", "green bold")
        } else if self.show_spinner {
            let spinner = Self::SPINNER_FRAMES[frame % Self::SPINNER_FRAMES.len()];
            theme.style_text(&spinner.to_string(), "cyan")
        } else {
            "◐".to_string()
        };

        content.push(format\!("{} {}", icon, stage_text));
        content.push(String::new());

        // Connection progress bar
        if progress.active_connections > 0 || \!matches\!(progress.stage, ShutdownStage::Complete) {
            let conn_bar = self.render_bar(
                progress.active_connections, 
                50, // Assumed max
                10
            );
            content.push(format\!(
                "Active connections: {} {}",
                conn_bar,
                progress.active_connections
            ));
        }

        // Task progress bar
        if progress.pending_tasks > 0 || \!matches\!(progress.stage, ShutdownStage::Complete) {
            let task_bar = self.render_bar(progress.pending_tasks, 15, 10);
            content.push(format\!(
                "Pending tasks:      {} {}",
                task_bar,
                progress.pending_tasks
            ));
        }

        // Timeout indicator
        let remaining = progress.timeout_seconds.saturating_sub(progress.elapsed_seconds);
        if remaining > 0 && \!matches\!(progress.stage, ShutdownStage::Complete) {
            content.push(format\!("Timeout:            {}s remaining", remaining));
        }

        content.push(String::new());

        // Resource cleanup status
        if self.show_resource_details && \!progress.resources_to_cleanup.is_empty() {
            content.push(theme.style_text("Resources:", "bold"));

            for resource in &progress.resources_to_cleanup {
                let (icon, style) = match &resource.status {
                    CleanupStatus::Complete => ("✓", "green"),
                    CleanupStatus::InProgress => ("◐", "cyan"),
                    CleanupStatus::Pending => ("○", "dim"),
                    CleanupStatus::Failed(_) => ("✗", "red"),
                };

                let status_text = match &resource.status {
                    CleanupStatus::Complete => "closed".to_string(),
                    CleanupStatus::InProgress => "draining".to_string(),
                    CleanupStatus::Pending => "pending".to_string(),
                    CleanupStatus::Failed(e) => format\!("failed: {}", e),
                };

                content.push(format\!(
                    "  {} {} ({})",
                    theme.style_text(icon, style),
                    resource.name,
                    status_text
                ));
            }
        }

        let panel = Panel::from_text(&content.join("\n"))
            .title("Graceful Shutdown")
            .rounded();

        output.renderable(&panel);
    }

    fn render_bar(&self, current: usize, max: usize, width: usize) -> String {
        let ratio = (current as f64 / max as f64).min(1.0);
        let filled = (ratio * width as f64) as usize;
        let empty = width - filled;
        format\!("{}{}" , "█".repeat(filled), "░".repeat(empty))
    }

    fn display_plain(&self, output: &RichOutput, progress: &ShutdownProgress) {
        let stage = match progress.stage {
            ShutdownStage::SignalReceived => "Signal received",
            ShutdownStage::StopAccepting => "Stop accepting",
            ShutdownStage::DrainingConnections => "Draining",
            ShutdownStage::WaitingForTasks => "Waiting tasks",
            ShutdownStage::CleaningResources => "Cleanup",
            ShutdownStage::Complete => "Complete",
        };

        output.plain(&format\!(
            "Shutdown: {} ({} connections, {} tasks, {}s timeout)",
            stage,
            progress.active_connections,
            progress.pending_tasks,
            progress.timeout_seconds.saturating_sub(progress.elapsed_seconds)
        ));

        for resource in &progress.resources_to_cleanup {
            let status = match &resource.status {
                CleanupStatus::Complete => "closed",
                CleanupStatus::InProgress => "draining",
                CleanupStatus::Pending => "pending",
                CleanupStatus::Failed(e) => e,
            };
            output.plain(&format\!("  - {}: {}", resource.name, status));
        }
    }
}
```

### Integration Point
