async fn graceful_shutdown(signal: ShutdownSignal) {
    let display = ShutdownDisplay {
        show_spinner: true,
        show_resource_details: true,
        update_interval_ms: 100,
    };

    let mut progress = ShutdownProgress { /* ... */ };
    let mut frame = 0;

    // Update loop (only in TTY mode)
    while \!matches\!(progress.stage, ShutdownStage::Complete) {
        display.display(&progress, frame);
        frame += 1;

        // Wait for next update
        sleep(Duration::from_millis(display.update_interval_ms)).await;

        // Update progress from actual state
        progress = get_current_shutdown_state();
    }

    // Final display
    display.display(&progress, 0);
}
